# Simple LLM-as-judge via OpenAI
def judge(prompt, actual, rubric):
    r = client.chat.completions.create(
        model='gpt-4o',
        messages=[{'role':'system','content':f'You are a strict grader.\nRubric: {rubric}\nReply JSON: {{"score":0-5,"reason":""}}'},
                  {'role':'user','content':f'Task: {prompt}\n\nResponse: {actual}'}],
        response_format={'type':'json_object'},
    )
    return json.loads(r.choices[0].message.content)
